4	 * The pod itself does no auth: Envoy validates the gateway JWT at the edge and routes on the
5	 * `sub` claim to `lmthing.user-<id>.svc`. So every call here just carries the bearer token and
6	 * talks to the chat origin. Locally (`lmthing serve`) pass base=http://localhost:8080 and no token.
7	 */
8	
9	export class Pod {
10	  /**
11	   * @param {object} o
12	   * @param {string} o.base      the pod/API origin (prod: https://lmthing.chat)
13	   * @param {string} [o.token]   gateway JWT (Envoy routes on its `sub` claim)
14	   * @param {string} [o.appBase] the SERVED-APP origin. In prod the app is NOT reachable under
15	   *   `<chat>/app/<id>/` — Envoy hands `/app/*` on the chat host to the static web SPA (nginx),
16	   *   which answers a GET with the SPA *shell* (a 200 `<!doctype>` that is not the app at all —
17	   *   a scenario asserting only "200 + <!doctype" false-passes) and a POST with **405**. The app
18	   *   is root-mounted on lmthing.app (`/<project>/`, `/<project>/api/<route>` — serve.ts's
19	   *   "Project-app ROOT mount"). Locally there is no split host, so apps stay under `/app/<id>/`.
20	   */
21	  constructor({ base, token, appBase }) {
22	    this.base = base;
23	    this.token = token;
24	    this.appBase = appBase ?? process.env.LM_APP_BASE ?? (/lmthing\.chat/.test(base) ? 'https://lmthing.app' : base);
25	    /** true when the app has its own host → root mount (no `/app` prefix). */
26	    this.appRootMounted = this.appBase !== this.base;
27	  }
28	
29	  /** The origin+prefix the SERVED app actually lives at (see `appBase`). */
30	  appOrigin(projectId) {
31	    return this.appRootMounted
32	      ? `${this.appBase}/${projectId}`
33	      : `${this.base}/app/${projectId}`;
34	  }
35	
36	  /** Absolute-URL variant of `req` (the served app is on a different origin than /api/*). */
37	  async reqAbs(method, url, body) {
38	    for (let attempt = 0; ; attempt++) {
39	      const res = await fetch(url, {
40	        method,
41	        headers: {
42	          ...(body !== undefined ? { 'content-type': 'application/json' } : {}),
43	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
44	        },
45	        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
46	      });
47	      const text = await res.text();
48	      let parsed = text;
49	      try {
50	        parsed = JSON.parse(text);
51	      } catch {
52	        /* html / raw */
53	      }
54	      // The activator MARKS its own response (`{waking:true}`) whatever status it uses (503/504),
55	      // so key on that marker — never on a bare 503, which for an app route is a real verdict.
56	      const waking =
57	        res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
58	      if (waking && attempt < 100) {
59	        await new Promise((r) => setTimeout(r, 3000));
60	        continue;
61	      }
62	      return { status: res.status, body: parsed };
63	    }
64	  }
65	
66	  async req(method, path, body, { raw = false } = {}) {
67	    // A scaled-to-zero pod answers with `504 {waking:true}` while the Envoy activator boots
68	    // it; that is a transient, not the endpoint's verdict. Retry idempotent-ish calls until
69	    // the pod is warm (bounded), so a read that lands on a cold pod self-heals instead of
70	    // throwing a spurious failure mid-scenario.
71	    //
72	    // The budget is minutes, not seconds. A pod that is ROLLING (a new image) or whose single
73	    // Node thread is stalled inside a long authoring turn keeps answering `waking` well past a
74	    // minute — the old 20×3s ≈ 60s gave up and threw `POST /api/sessions → 503 {waking:true}`,
75	    // killing a multi-hour run over a transient the harness was written to absorb.
76	    for (let attempt = 0; ; attempt++) {
77	      const res = await fetch(`${this.base}${path}`, {
78	        method,
79	        headers: {
80	          ...(body !== undefined ? { 'content-type': 'application/json' } : {}),
81	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
82	        },
83	        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
84	      });
85	      const text = await res.text();
