107	    }
108	  }
109	
110	  // ── projects ────────────────────────────────────────────────────────────
111	  listProjects = () => this.req('GET', '/api/projects');
112	  createProject = (name) => this.req('POST', '/api/projects', { name });
113	  deleteProject = (id) => this.req('DELETE', `/api/projects/${id}`);
114	  listSpaces = (projectId) => this.req('GET', `/api/projects/${projectId}/spaces`);
115	  listIntegrations = (projectId) => this.req('GET', `/api/projects/${projectId}/integrations`);
116	  projectSessions = (projectId) => this.req('GET', `/api/projects/${projectId}/sessions`);
117	
118	  // ── files (the whole point: assert what the agents actually WROTE) ───────
119	  fsTree = () => this.req('GET', '/api/fs/tree');
120	  readFile = (path) => this.req('GET', `/api/fs/read?path=${encodeURIComponent(path)}`);
121	  writeFile = (path, content) => this.req('PUT', '/api/fs/write', { path, content });
122	
123	  /** Read one authored file of a project (`<project>/pages/_layout.tsx`, `api/…`) — assert what the agent WROTE. */
124	  async readProjectFile(projectId, rel) {
125	    const r = await this.readFile(`${projectId}/${rel}`).catch(() => null);
126	    return typeof r === 'string' ? r : (r?.content ?? '');
127	  }
128	
129	  // ── store ───────────────────────────────────────────────────────────────
130	  storeSpaces = () => this.req('GET', '/api/store/spaces');
131	  installSpace = (spaceId, projectId = 'user', force = false) =>
132	    this.req('POST', '/api/store/spaces/install', { spaceId, projectId, force });
133	  storeApps = () => this.req('GET', '/api/apps');
134	  installApp = (appId, projectId, force = false) =>
135	    this.req('POST', '/api/apps/install', { appId, ...(projectId ? { projectId } : {}), force });
136	
137	  // ── project-app runtime ─────────────────────────────────────────────────
138	  appManifest = (projectId) => this.req('GET', `/api/projects/${projectId}/app`);
139	  appBuild = (projectId) => this.req('POST', `/api/projects/${projectId}/app/build`);
140	  appData = (projectId, table) => this.req('GET', `/api/projects/${projectId}/app/data/${table}`);
141	  /** GET the SERVED app page — on its real origin (see `appBase`), not the SPA shell. */
142	  appPage = (projectId, path = '') => this.reqAbs('GET', `${this.appOrigin(projectId)}/${path}`);
143	
144	  // ── hooks & events ──────────────────────────────────────────────────────
145	  /** List every loaded hook across projects (`GET /api/hooks`). */
146	  listHooks = () => this.req('GET', '/api/hooks');
147	  /**
148	   * Call an app's OWN API route — the routes its pages actually fetch, on the app's real origin
149	   * (`<app-host>/<project>/api/<route>`). This is the layer the user sees: a page whose data API
150	   * returns rows can still render zeros because its own aggregation route 500s.
151	   */
152	  appApi = (projectId, route, body, method = 'POST') =>
153	    this.reqAbs(method, `${this.appOrigin(projectId)}/api/${String(route).replace(/^\//, '')}`, body);
154	  /** The one authoritative hook-run path (crond, boot catch-up and Studio all use it).
155	   *  The slug is a single path segment and may contain `:`/`@` (space hooks are
156	   *  `<spaceId>:<base>`; emitters are `@emitter:<scope>:<name>`) — encode it. */
157	  runHook = (projectId, slug) =>
158	    this.req('POST', `/api/projects/${projectId}/hooks/${encodeURIComponent(slug)}/run`, {});
159	  /** Run a cron emitter def by its pseudo-slug (`@emitter:<scope>:<name>`). */
160	  runEmitter = (projectId, scope, name) => this.runHook(projectId, `@emitter:${scope}:${name}`);
161	
162	  /**
163	   * Deliver an inbound webhook exactly as an external provider would.
164	   * `headers` carries the provider's signature headers — the pod verifies BEFORE emit.
165	   *
166	   * NOTE the bearer token: in prod the pod is reached through Envoy, which routes on the
167	   * gateway JWT's `sub` claim — without it the edge answers `401 Jwt is missing` and the
168	   * request never reaches the pod. The real public path (gateway `/api/inbound/<token>/<path>`)
169	   * is a 202 fire-and-forget broker that hides the pod's own status code, so a scenario that
170	   * needs to assert 200/401/404 + `{events:n}` must deliver to the pod directly. The pod
171	   * itself does no auth: verification is the provider signature, exactly as in production.
172	   */
173	  async inbound(path, body, headers = {}) {
174	    const payload = typeof body === 'string' ? body : JSON.stringify(body);
175	    // A scaled-to-zero pod answers the FIRST hit with `504 {waking:true}` (the Envoy
176	    // instant-wake activator) while it boots — that is not the def's real verdict. Retry
177	    // the exact same signed bytes until the woken pod actually runs verify→emit. The body
178	    // is byte-identical, but inbound dedupe only kicks in AFTER a successful verify, so a
179	    // retry of a request the pod never processed is not deduped.
180	    for (let attempt = 0; ; attempt++) {
181	      const res = await fetch(`${this.base}/api/inbound/${path}`, {
182	        method: 'POST',
183	        headers: {
184	          'content-type': 'application/json',
185	          ...(this.token ? { authorization: `Bearer ${this.token}` } : {}),
186	          ...headers,
187	        },
188	        body: payload,
189	      });
190	      const text = await res.text();
191	      let parsed = text;
192	      try {
193	        parsed = JSON.parse(text);
194	      } catch {
195	        /* raw */
196	      }
197	      const waking = res.status === 504 || (parsed && typeof parsed === 'object' && parsed.waking === true);
198	      if (!waking || attempt >= 100) return { status: res.status, body: parsed };
199	      await new Promise((r) => setTimeout(r, 3000));
200	    }
201	  }
202	
203	  // ── uploads (chat attachments) ──────────────────────────────────────────
204	  /**
205	   * The mediaType decides the pod's ROUTE, not just a label: `image/*` goes to system-vision,
206	   * `audio/*` is transcribed at ingest, everything else goes to system-files. So a `.mp3` sent as
207	   * `application/octet-stream` is never transcribed, and a scenario asserting "a spoken-only fact
208	   * reached a row" fails for a reason that has nothing to do with the product. Every fixture type the
209	   * scenarios actually upload must be in this table.
210	   */
211	  static MEDIA_TYPES = {
212	    '.md': 'text/markdown',
213	    '.txt': 'text/plain',
214	    '.csv': 'text/csv',
215	    '.json': 'application/json',
216	    '.pdf': 'application/pdf',
217	    '.jpg': 'image/jpeg',
218	    '.jpeg': 'image/jpeg',
219	    '.png': 'image/png',
220	    '.webp': 'image/webp',
221	    '.gif': 'image/gif',
222	    '.mp3': 'audio/mpeg',
223	    '.m4a': 'audio/mp4',
224	    '.wav': 'audio/wav',
225	    '.ogg': 'audio/ogg',
226	    '.webm': 'audio/webm',
227	    '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
228	    '.xls': 'application/vnd.ms-excel',
229	    '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
230	  };
231	
232	  /**
233	   * Upload a local file as a chat attachment (the UI's "load a file" action).
234	   * `POST /api/uploads` takes base64 + mediaType and returns an AttachmentRef
235	   * (`{id, kind, mediaType, filename?, url}`) that a message then references by id.
236	   * Pair with `ThingSession.sendWithAttachments()` (WS path — HTTP /message drops attachments).
237	   *
238	   * Throws on an unknown extension rather than silently sending `application/octet-stream` — a
239	   * misrouted attachment turns a real product failure into a green test (see MEDIA_TYPES).
240	   */
241	  async upload(filePath, { mediaType, filename } = {}) {
242	    const { readFileSync } = await import('node:fs');
243	    const { basename, extname } = await import('node:path');
244	    const bytes = readFileSync(filePath);
245	    const ext = extname(filePath).toLowerCase();
246	    const mt = mediaType ?? Pod.MEDIA_TYPES[ext];
247	    if (!mt) {
248	      throw new Error(
249	        `upload(${basename(filePath)}): no mediaType known for "${ext}" — pass { mediaType } explicitly ` +
250	          `or add it to Pod.MEDIA_TYPES. Guessing octet-stream would misroute it (no vision, no transcription).`,
251	      );
252	    }
253	    const ref = await this.req('POST', '/api/uploads', {
254	      filename: filename ?? basename(filePath),
255	      mediaType: mt,
256	      data: bytes.toString('base64'),
257	    });
258	    return ref;
259	  }
260	
261	  // ── accounting ──────────────────────────────────────────────────────────
262	  /** Pod-global token/cost ledger — includes the DELEGATE tree, not just top-level turns. */
263	  sessionLedger = () => this.req('GET', '/api/session-ledger');
264	  /** The gateway's spend-window report, as the pod sees it. */
265	  budget = () => this.req('GET', '/api/budget');
266	
267	  // ── env / lifecycle ─────────────────────────────────────────────────────
268	  getEnv = () => this.req('GET', '/api/env');
269	  /** Restart the pod process (used by the auto-resume scenario). Pod exits ~100ms later. */
270	  restart = () => this.req('POST', '/api/restart', {}).catch(() => ({ ok: true }));
271	}
