362	  }
363	
364	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
365	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
366	  /** Did it delegate to this `space/agent` (or just this space)? */
