372	  consentCards = () => this.asks.filter((a) => a.descriptor?.type === 'ConsentCard');
373	
374	  /** Full session totals — for the performance table in the scenario report. */
375	  stats() {
376	    const t = this.turn(0, 0);
377	    return {
378	      events: this.events.length,
379	      llmCalls: t.llmCalls,
380	      tokens: t.tokens,
381	      errors: t.errors.length,
