389	function delegateRef(args) {
390	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
391	  if (args && typeof args === 'object') {
392	    const { space, agent, action } = args;
393	    return [space, agent, action].filter(Boolean).join('/');
394	  }
395	  return String(args);
396	}
