399	export function textOf(events) {
400	  const out = [];
401	  for (const e of events) {
402	    if (e.type === 'display') {
403	      const d = e.descriptor;
404	      const s =
405	        typeof d === 'string'
406	          ? d
407	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
408	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
409	    }
410	  }
411	  return out.join('\n');
412	}
413	
414	/** The LAST thing THING displayed — its final reply for this turn (see `turn().lastText`). */
415	export function lastTextOf(events) {
416	  for (let i = events.length - 1; i >= 0; i--) {
417	    const e = events[i];
418	    if (e.type !== 'display') continue;
419	    const d = e.descriptor;
420	    const s =
421	      typeof d === 'string'
422	        ? d
423	        : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
424	    const out = typeof s === 'string' ? s : JSON.stringify(s);
425	    if (out && out.trim()) return out;
426	  }
